CREATE VIEW `ads_PayorderNotify_view` (`Id`, `CreateTime` COMMENT "创建时间", `CooOrderId` COMMENT "合作支付订单号", `Sku` COMMENT "品类", `PackageId` COMMENT "包Id", `PayType` COMMENT "支付类型,appstore,googleplay", `RawCooOrderId` COMMENT "原始订单号", `OrderData` COMMENT "原始订单信息", `OrderType` COMMENT "订单类型,订阅1/普通订单2", `UserId` COMMENT "可能的用户Id", `OrderId` COMMENT "可能的订单号", `ProductId` COMMENT "产品id", `NotifyType` COMMENT "通知的类型,对应的苹果谷歌的NotifyType", `FirstSubOrderSerialId` COMMENT "首次订阅的订单序列号") AS SELECT `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`Id`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`CreateTime`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`CooOrderId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`Sku`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`PackageId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`PayType`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`RawCooOrderId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`OrderData`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`OrderType`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`UserId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`OrderId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`ProductId`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`NotifyType`, `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`.`FirstSubOrderSerialId`
FROM `ods`.`ods_tidb_sharpengine_pay_PayOrderNotify`;